previewCss:
.darma-loader-darma-custom-512 {color: var(--loader-color, #e11d48);
  --loader-secondary-color: var(--loader-secondary-color, #fb7185);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #e11d48);
   position: relative;
   animation: darma-loader-darma-custom-512-l8-0 2.5s infinite linear alternate;
}
.darma-loader-darma-custom-512:before  {
  content: "";
   position: absolute;
   inset: 0;
   background: var(--loader-secondary-color, #fb7185);
   transform: translate(100%);
   transform-origin: top left;
   animation: darma-loader-darma-custom-512-l8-1 .5s infinite alternate;
}
@keyframes darma-loader-darma-custom-512-l8-0  {
  0% ,19.9%, 80%,100% {transform: scale(1,1)}
20%,39.9% {transform: scale(-1,1)}
40%,59.9% {transform: scale(-1,-1)}
60%,79.9% {transform: scale(1,-1)}
}
@keyframes darma-loader-darma-custom-512-l8-1  {
  0%,20% {transform: translate(100%) rotate(0)}
80%,100% {transform: translate(100%) rotate(-180deg)}
}

